final:
module top_module(
    input x,
    input b,
    output t
);
    assign t = x ~^ b;
endmodule

module Q(
    input x,
    input b,
    output t
);
    assign t = x ~^ b;
endmodule

module top_module(
    input x,
    input b,
    output t
);
    wire p1_out, p2_out, q1_out, q2_out;
    wire and_out, nand_out;

    P p1(.x(x), .b(b), .t(p1_out));
    P p2(.x(x), .b(b), .t(p2_out));
    Q q1(.x(x), .b(b), .t(q1_out));
    Q q2(.x(x), .b(b), .t(q2_out));

    assign and_out = p1_out & q1_out;
    assign nand_out = ~(p2_out & q2_out);

    assign t = and_out | nand_out;
endmodule
